html: <!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta http-equiv="X-UA-Compatible" content="IE=edge">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Timeline</title>
    <link href="https://cdn.tailwindcss.com" rel="stylesheet">
</head>
<body>
    <header class="bg-gray-800 text-white p-4">
        <h1 class="text-3xl font-bold">Timeline</h1>
    </header>
    <main class="container mx-auto p-4">
        <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            <div class="bg-white p-4 rounded shadow">
                <h2 class="text-2xl font-bold mb-4">Past Events</h2>
                <ul class="event-list">
                    <li class="event mb-4">
                        <h3 class="text-xl font-bold">Event 1</h3>
                        <p>December 12, 2021</p>
                    </li>
                    <li class="event mb-4">
                        <h3 class="text-xl font-bold">Event 2</h3>
                        <p>January 15, 2022</p>
                    </li>
                </ul>
            </div>
            <div class="bg-white p-4 rounded shadow">
                <h2 class="text-2xl font-bold mb-4">Upcoming Events</h2>
                <ul class="event-list">
                    <li class="event mb-4">
                        <h3 class="text-xl font-bold">Event 3</h3>
                        <p>February 20, 2022</p>
                    </li>
                    <li class="event mb-4">
                        <h3 class="text-xl font-bold">Event 4</h3>
                        <p>March 25, 2022</p>
                    </li>
                </ul>
            </div>
            <div class="bg-white p-4 rounded shadow">
                <h2 class="text-2xl font-bold mb-4">Current Event</h2>
                <ul class="event-list">
                    <li class="event mb-4">
                        <h3 class="text-xl font-bold">Event 5</h3>
                        <p>April 1, 2022</p>
                    </li>
                </ul>
            </div>
        </div>
    </main>
    <script>
        // Add a click event listener to each event
        const events = document.querySelectorAll(".event");
        events.forEach((event) => {
            event.addEventListener("click", () => {
                console.log("Event clicked");
            });
        });
    </script>
</body>
</html>
css: /* Add some basic styling to the timeline sections */
.main-container {
    max-width: 1200px;
    margin: 0 auto;
}
.section-header {
    background-color: #333;
    color: #fff;
    padding: 1rem;
}
.event-list {
    list-style: none;
    padding: 0;
    margin: 0;
}
.event {
    padding: 1rem;
    border-bottom: 1px solid #ddd;
}
.event:hover {
    background-color: #f7f7f7;
}
@media (max-width: 768px) {
    .grid {
        grid-template-columns: 1fr;
    }
}
@media (min-width: 768px) {
    .grid {
        grid-template-columns: 1fr 1fr;
    }
}
@media (min-width: 1024px) {
    .grid {
        grid-template-columns: 1fr 1fr 1fr;
    }
}
